/// Overwrite every static (game-owned) slot with the in-game color;
/// dynamic slots (64-159) keep the map/pack values.
pub fn apply_game_statics(palette: &mut [u8]) {
	for slot in 0..=255u8 {
		if DYNAMIC_SLOTS.contains(&slot) {
			continue;
		}
		let at = slot as usize * 3;
		palette[at..at + 3].copy_from_slice(&GAME_PALETTE[at..at + 3]);
	}
}
